import{_ as s,o as a,c as i,aj as t}from"./chunks/framework.BASLC-SQ.js";const g=JSON.parse('{"title":"SIP003: A simplified plugin design for shadowsocks","description":"","frontmatter":{},"headers":[],"relativePath":"doc/sip003.md","filePath":"doc/sip003.md","lastUpdated":1776149954000}'),o={name:"doc/sip003.md"},r={xmlns:"http://www.w3.org/2000/svg",viewBox:"0 0 720 280",style:{display:"block",margin:"1em auto",width:"100%",height:"auto","max-width":"720px"},role:"img","aria-label":"SIP003 plugin architecture: SS client and SS server each connect via local loopback to a plugin client/server tunnel, with obfuscated public internet traffic between the two plugin endpoints"};function n(l,e,p,h,c,d){return a(),i("div",null,[e[1]||(e[1]=t('<h1 id="sip003-a-simplified-plugin-design-for-shadowsocks" tabindex="-1">SIP003: A simplified plugin design for shadowsocks <a class="header-anchor" href="#sip003-a-simplified-plugin-design-for-shadowsocks" aria-label="Permalink to &quot;SIP003: A simplified plugin design for shadowsocks&quot;">​</a></h1><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>The plugin of shadowsocks is very similar to the <a href="https://gitweb.torproject.org/torspec.git/tree/pt-spec.txt" target="_blank" rel="noreferrer">Pluggable Transport</a> plugins from Tor project. Unlike the SOCKS5 proxy design in PT, every SIP003 plugin works as a tunnel (or called local port forwarding). This design aims to avoid per-connection arguments in PT, leading to much easier implementation.</p>',3)),(a(),i("svg",r,[...e[0]||(e[0]=[t('<defs><marker id="sip003-arr" viewBox="0 0 10 10" refX="9" refY="5" markerWidth="7" markerHeight="7" orient="auto-start-reverse"><path d="M0,0 L10,5 L0,10 z" fill="currentColor"></path></marker></defs><g fill="none" stroke="currentColor"><rect x="20" y="20" width="140" height="50" rx="4"></rect><rect x="290" y="20" width="260" height="50" rx="4"></rect><rect x="20" y="210" width="140" height="50" rx="4"></rect><rect x="290" y="210" width="260" height="50" rx="4"></rect><line x1="160" y1="45" x2="290" y2="45"></line><line x1="160" y1="235" x2="290" y2="235"></line><path d="M550 45 L620 45 L620 235 L550 235" stroke-dasharray="0"></path><line x1="620" y1="140" x2="690" y2="140" marker-end="url(#sip003-arr)"></line></g><g fill="currentColor" font-family="ui-monospace,SFMono-Regular,Menlo,Consolas,monospace" font-size="13" text-anchor="middle"><text x="90" y="50">SS Client</text><text x="420" y="50">Plugin Client (Tunnel)</text><text x="90" y="240">SS Server</text><text x="420" y="240">Plugin Server (Tunnel)</text><text x="225" y="38" font-size="11">Local Loopback</text><text x="225" y="228" font-size="11">Local Loopback</text><text x="360" y="135" font-size="12">Public Internet</text><text x="360" y="152" font-size="11" opacity="0.75">(Obfuscated / Transformed traffic)</text></g>',3)])])),e[2]||(e[2]=t('<h2 id="life-cycle-of-a-plugin" tabindex="-1">Life cycle of a plugin <a class="header-anchor" href="#life-cycle-of-a-plugin" aria-label="Permalink to &quot;Life cycle of a plugin&quot;">​</a></h2><p>Very similar to PT, the plugin client/server is started as child process of shadowsocks client/server.</p><p>If any error happens, the child process of plugin should exit with a error code. Then, the parent process of shadowsocks stops as well (SIGCHLD).</p><p>When a shadowsocks client/server is stopped by user, the child process of plugin will also be terminated.</p><h2 id="passing-arguments-to-a-plugin" tabindex="-1">Passing arguments to a plugin <a class="header-anchor" href="#passing-arguments-to-a-plugin" aria-label="Permalink to &quot;Passing arguments to a plugin&quot;">​</a></h2><p>A plugin accepts arguments through environment variables.</p><p>a. Four <strong>MUST-HAVE</strong> environment variables are <code>SS_REMOTE_HOST</code>, <code>SS_REMOTE_PORT</code>, <code>SS_LOCAL_HOST</code> and <code>SS_LOCAL_PORT</code>. <code>SS_REMOTE_HOST</code> and <code>SS_REMOTE_PORT</code> are the hostname and port of the remote plugin service. <code>SS_LOCAL_HOST</code> and <code>SS_LOCAL_PORT</code> are the hostname and port of the local shadowsocks or plugin service.</p><p>b. One <strong>OPTIONAL</strong> environment variable is <code>SS_PLUGIN_OPTIONS</code>. If a plugin requires additional arguments, like path to a config file, these arguments can be passed as extra options in a formatted string. An example is &#39;obfs=http;obfs-host=www.baidu.com&#39;, where semicolons, equal signs and backslashes <strong>MUST</strong> be escaped with a backslash.</p><h2 id="compatibility-with-pt" tabindex="-1">Compatibility with PT <a class="header-anchor" href="#compatibility-with-pt" aria-label="Permalink to &quot;Compatibility with PT&quot;">​</a></h2><p>For all the plugins from Tor projects, there are two possible ways to support them. 1) We can fork these plugins and modify them to support SIP003, e.g. <a href="https://github.com/madeye/obfs4-tunnel" target="_blank" rel="noreferrer">obfs4-tunnel</a>. 2) Implement a adapter of PT as SIP003 plugin.</p><h2 id="licenses-of-plugins" tabindex="-1">Licenses of plugins <a class="header-anchor" href="#licenses-of-plugins" aria-label="Permalink to &quot;Licenses of plugins&quot;">​</a></h2><p>As all plugin services should run in a separate process, they can pick any license they like. There is no GPL restrictions for any plugin providers.</p><h2 id="restrictions" tabindex="-1">Restrictions <a class="header-anchor" href="#restrictions" aria-label="Permalink to &quot;Restrictions&quot;">​</a></h2><p>a. Plugin over plugin is NOT supported. Only one plugin can be enabled when a shadowsocks service is started. If you really need this feature, implement a plugin-over-plugin transport as a SIP003 plugin. b. Only TCP traffic is forwarded. For now, there is no plan to support UDP traffic forwarding.</p><h2 id="example-projects" tabindex="-1">Example projects <a class="header-anchor" href="#example-projects" aria-label="Permalink to &quot;Example projects&quot;">​</a></h2><ul><li>A SIP003 plugin for traffic obfuscating: <a href="https://github.com/shadowsocks/simple-obfs" target="_blank" rel="noreferrer">simple-obfs</a>.</li><li>A shadowsocks implementation supporting SIP003: <a href="https://github.com/shadowsocks/shadowsocks-libev" target="_blank" rel="noreferrer">shadowsocks/shadowsocks-libev</a>.</li></ul><h2 id="command-line-example" tabindex="-1">Command line example <a class="header-anchor" href="#command-line-example" aria-label="Permalink to &quot;Command line example&quot;">​</a></h2><p>On the server:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ss-server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> obfs-server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --plugin-opts</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;obfs=http&quot;</span></span></code></pre></div><p>On the client:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ss-local</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config.json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> obfs-local</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --plugin-opts</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;obfs=http;obfs-host=www.baidu.com&quot;</span></span></code></pre></div><h2 id="known-good-sip003-plugins" tabindex="-1">Known good SIP003 plugins <a class="header-anchor" href="#known-good-sip003-plugins" aria-label="Permalink to &quot;Known good SIP003 plugins&quot;">​</a></h2><ul><li>GoQuiet: <a href="https://github.com/cbeuw/GoQuiet" target="_blank" rel="noreferrer">https://github.com/cbeuw/GoQuiet</a></li><li>Cloak: <a href="https://github.com/cbeuw/Cloak" target="_blank" rel="noreferrer">https://github.com/cbeuw/Cloak</a></li><li>Kcptun: <a href="https://github.com/shadowsocks/kcptun" target="_blank" rel="noreferrer">https://github.com/shadowsocks/kcptun</a></li><li>V2ray-plugin: <a href="https://github.com/shadowsocks/v2ray-plugin" target="_blank" rel="noreferrer">https://github.com/shadowsocks/v2ray-plugin</a></li></ul>',23))])}const f=s(o,[["render",n]]);export{g as __pageData,f as default};
